"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"📦 Преимущество: можно безопасно кэшировать значения даже для сложных аргументов ("},{"type":"text","marks":[{"type":"code"}],"text":"arrays"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"code"}],"text":"objects"},{"type":"text","text":")."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🔥 3. Продвинутая версия с ограничением размера кэша (LRU Cache)"}]},{"type":"blockquote","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Чтобы кэш не рос бесконечно и не “съел” память."}]}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function memoize(fn, limit = 5) {
  const cache = new Map();

  return function (...args) {
    const key = JSON.stringify(args);

    if (cache.has(key)) {
      // обновляем порядок использования
      const value = cache.get(key);
      cache.delete(key);
      cache.set(key, value);
      return value;
    }

    const result = fn(...args);
    cache.set(key, result);

    // если кэш слишком большой — удаляем старейший элемент
    if (cache.size > limit) {
      const oldestKey = cache.keys().next().value;
      cache.delete(oldestKey);
    }

    return result;
  };
}
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"📈 Теперь кэш “скользящий”: хранит последние N вызовов, что полезно для реальных приложений."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🧠 4. Пример реального применения — мемоизация рекурсивной функции (фибоначчи)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function memoize(fn) {
  const cache = {};
  return function (n) {
    if (n in cache) return cache[n];
    const result = fn(n);
    cache[n] = result;
    return result;
  };
}

