const scheduleTimeout = (fn) => setTimeout(fn, 0);                // простой
const scheduleRAF = (fn) => requestAnimationFrame(fn);            // мягко для UI
const scheduleIdle = (fn) => requestIdleCallback(fn, { timeout: 50 }); // когда есть "простой" (fallback обязателен)

// Чанкер по времени: работает ~N миллисекунд, затем "уступает" цикл
export function runSliced(work, { budgetMs = 4, schedule = scheduleRAF } = {}) {
  return new Promise((resolve, reject) => {
    try {
      const step = (deadlineLike) => {
        const start = performance.now();
        while (work.hasMore()) {
          work.doOne();
          const now = performance.now();
          // Если вышли за бюджет — уступаем кадр
          if (now - start >= budgetMs) {
            schedule(step);
            return;
          }
        }
        resolve();
      };
      schedule(step);
    } catch (e) { reject(e); }
  });
}

