function runSlicedNode(work, { iterationsPerSlice = 50_000, schedule = scheduleImmediate } = {}) {
  return new Promise((resolve, reject) => {
    try {
      const step = () => {
        let n = iterationsPerSlice;
        while (work.hasMore() && n--) {
          work.doOne();
